package com.grit.liferecorder.ui.calendar
import androidx.lifecycle.ViewModel; import androidx.lifecycle.viewModelScope; import com.grit.liferecorder.core.date.DateUtils; import com.grit.liferecorder.data.repository.*; import kotlinx.coroutines.flow.*; import kotlinx.coroutines.launch; import java.time.*
data class CalendarUiState(val month:YearMonth=YearMonth.now(),val selectedDate:String=DateUtils.today(),val days:List<DayAggregate> = emptyList(),val selected:DayAggregate?=null)
class CalendarViewModel(private val calendarRepository:CalendarRepository, private val journalRepository:JournalRepository):ViewModel(){ private val month=MutableStateFlow(YearMonth.now()); private val selectedDate=MutableStateFlow(DateUtils.today()); val state:StateFlow<CalendarUiState> = month.flatMapLatest{ ym-> calendarRepository.observeMonth(ym).combine(selectedDate){days,sel-> CalendarUiState(ym,sel,days,days.find{it.date==sel}) } }.stateIn(viewModelScope,SharingStarted.WhileSubscribed(5000),CalendarUiState()); fun previousMonth(){month.value=month.value.minusMonths(1)}; fun nextMonth(){month.value=month.value.plusMonths(1)}; fun select(date:String){selectedDate.value=date}; fun saveJournal(note:String){ viewModelScope.launch{ if(note.isNotBlank()) journalRepository.save(selectedDate.value,note) } } }
